void solve(int CASE)
{
	int n; cin >> n;

	var mp = map<int, vector<int>>();
	var Q = [&](int x)->vector<int> {
		if (mp.count(x))return mp[x];

		cout << '?' << ' ' << x << endl;
		cout.flush();
		var res = vector<int>();
		int n; cin >> n;
		fa(i, 1, n) {
			int x; cin >> x;
			res.pb(x);
		}

		return mp[x] = res;
		};

	var p = set<pii>();
	var cnt = vector<int>(n + 1);
	var vis = vector<bool>(n + 1);
	int now = 1;
	var dfs = [&](var dfs, int u, vector<int> pre)->void {
		vis[u] = 1;
		cnt[u] = 1;

		now++;
		pre.pb(u);

		while (1) {
			var res = Q(now);

			if (res.size() <= pre.size())break;

			bool ok = 1;
			fa(i, 0, vs(pre))if (pre[i] != res[i]) {
				ok = 0;
				break;
			}
			if (!ok)break;

			int v = res.back();
			p.insert({ u,v });

			if (vis[v])now += cnt[v];
			else dfs(dfs, v, pre);
			cnt[u] += cnt[v];
		}
		};
	fa(i, 1, n) {
		if (vis[i])now += cnt[i];
		else dfs(dfs, i, {});
	}

	//fa(i, 1, n)cout << cnt[i] << ' ';
	//cout << endl;

	cout << "!" << ' ' << p.size() << endl;
	for (const var& [x, y] : p)cout << x << ' ' << y << endl;
	cout.flush();
	return;
}
